// Sanitize the site callback URL (allowlist: only our own domains may receive
// qualification callbacks with the shared secret) and derive a research URL
// from the lead's email domain, skipping free-mail providers.
const item = $input.first().json;
const CALLBACK_ALLOW = /^https:\/\/(highcraft\.io|www\.highcraft\.io|YOUR_SITE_PROJECT[a-z0-9.-]*\.vercel\.app)\/api\/estimate\/qualification\/?$/;
const raw = String(item.callback_url_raw || '').trim();
const callback_url = CALLBACK_ALLOW.test(raw) ? raw.replace(/\/?$/, '/') : '';
const FREE_MAIL = new Set(['gmail.com','googlemail.com','outlook.com','hotmail.com','live.com','yahoo.com','icloud.com','me.com','proton.me','protonmail.com','ukr.net','i.ua','meta.ua','mail.ru','yandex.ru','aol.com','gmx.com','pm.me','msn.com','example.com','example.dev']);
const emailDomain = (String(item.email || '').split('@')[1] || '').toLowerCase().trim();
const research_url = emailDomain && emailDomain.includes('.') && !FREE_MAIL.has(emailDomain) ? `https://${emailDomain}` : '';
return [{ json: { ...item, callback_url, research_url } }];

// Boil the fetched homepage down to a short research summary the qualifier can
// use. Empty summary when the fetch failed or returned nothing useful.
const base = $('Prep context').first().json;
let research_summary = '';
try {
  const resp = $input.first().json || {};
  const html = typeof resp.data === 'string' ? resp.data : (typeof resp.body === 'string' ? resp.body : '');
  if (html && html.length > 100) {
    const title = (html.match(/<title[^>]*>([^<]*)<\/title>/i) || [])[1] || '';
    const descMatch = html.match(/<meta[^>]+name=["']description["'][^>]*content=["']([^"']*)["']/i) || html.match(/<meta[^>]+content=["']([^"']*)["'][^>]*name=["']description["']/i);
    const desc = (descMatch || [])[1] || '';
    const text = html
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&[a-zA-Z#0-9]+;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    const parts = [];
    if (title.trim()) parts.push('Site title: ' + title.trim());
    if (desc.trim()) parts.push('Meta description: ' + desc.trim());
    if (text) parts.push('Page text: ' + text.slice(0, 1500));
    research_summary = parts.join('\n').slice(0, 1900);
  }
} catch (e) {
  research_summary = '';
}
return [{ json: { ...base, research_summary } }];

// Page token + URL for the hosted proposal page, the proposal JSON as a string
// for storage, and a plain-text rendering used by the Telegram fallback path.
const out = $input.first().json.output;
const p = typeof out === 'string' ? JSON.parse(out) : out;
// Normalize metric values: bare numbers with a 'percent ...' label become '40%'.
if (p.case_study && Array.isArray(p.case_study.metrics)) {
  for (const m of p.case_study.metrics) {
    if (/^\d+$/.test(String(m.value)) && /^(percent|відсот|процент)/i.test(String(m.label || ''))) {
      m.value = m.value + '%';
      m.label = String(m.label).replace(/^(percent|відсотків|відсотки|процентов|проценты)\s*/i, '');
    }
  }
}
const rowId = $('Log lead').first().json.id;
function makeToken() {
  try {
    const a = new Uint8Array(16);
    crypto.getRandomValues(a);
    return Array.from(a, (b) => b.toString(16).padStart(2, '0')).join('');
  } catch (e) {
    return Array.from({ length: 32 }, () => '0123456789abcdef'[Math.floor(Math.random() * 16)]).join('');
  }
}
const page_token = makeToken();
const proposal_page_url = `https://YOUR_N8N_HOST/webhook/proposal?id=${rowId}&t=${page_token}`;
const L = [];
L.push('DRAFT - review before sending');
L.push('');
L.push(p.title || 'Proposal');
L.push(`${p.client_company || ''}${p.client_name ? ' / ' + p.client_name : ''}`);
L.push('');
L.push('What we heard:');
for (const b of p.what_we_heard || []) L.push('- ' + b);
L.push('');
L.push('Proposed solution:');
for (const s of p.proposed_solution || []) L.push(`- ${s.title}: ${s.desc}`);
L.push('');
L.push(`First step (${(p.first_step && p.first_step.duration) || 'two weeks'}):`);
for (const b of (p.first_step && p.first_step.bullets) || []) L.push('- ' + b);
L.push('');
L.push('Timeline:');
for (const t of p.timeline || []) L.push(`- ${t.phase} (${t.duration}): ${t.desc}`);
if (p.case_study) {
  L.push('');
  L.push('Proof: ' + (p.case_study.title || ''));
  if (p.case_study.body) L.push(p.case_study.body);
  const m = (p.case_study.metrics || []).map((x) => `${x.value} ${x.label}`).join(', ');
  if (m) L.push(m);
  if (p.case_study.relevance) L.push('Why this matters here: ' + p.case_study.relevance);
}
L.push('');
L.push('Why HighCraft:');
for (const b of p.why_us || []) L.push('- ' + b);
L.push('');
L.push('Investment: ' + (p.investment_note || ''));
L.push('');
L.push('Next steps:');
(p.next_steps || []).forEach((s, i) => L.push(`${i + 1}. ${s}`));
if ((p.call_slots || []).length) L.push('Suggested slots: ' + p.call_slots.join(' or '));
let proposal_text = L.join('\n');
if (proposal_text.length > 3400) proposal_text = proposal_text.slice(0, 3390) + '\n[...]';
return [{ json: { proposal_json: JSON.stringify(p), page_token, proposal_page_url, proposal_text, row_id: rowId } }];

// Turn the proposal JSON into Google Docs batchUpdate requests: one insertText
// with the whole document, then paragraph/text styles and bullets by range.
// Docs indexes are UTF-16 code units, which matches JS string lengths.
const p = JSON.parse($('Prepare proposal assets').first().json.proposal_json);
let text = '';
const h2s = [];
const bolds = [];
const bulletRanges = [];
function line(s) {
  const start = text.length;
  text += (s || '') + '\n';
  return [start, start + (s || '').length];
}
const draftR = line('DRAFT - review before sending');
line('');
const titleR = line(p.title || 'Proposal');
const subR = line(`${p.client_company || ''}${p.client_name ? ' · ' + p.client_name : ''}`);
line('');
function section(h, body) {
  h2s.push(line(h));
  body();
  line('');
}
function bullets(arr) {
  const s = text.length;
  for (const b of arr || []) line(b);
  if (text.length > s) bulletRanges.push([s, text.length]);
}
section('What we heard', () => bullets(p.what_we_heard));
section('Proposed solution', () => {
  for (const s of p.proposed_solution || []) {
    bolds.push(line(s.title));
    line(s.desc);
  }
});
section('First step: ' + ((p.first_step && p.first_step.duration) || 'two weeks'), () => bullets(p.first_step && p.first_step.bullets));
section('Timeline', () => {
  for (const t of p.timeline || []) line(`${t.phase} (${t.duration}): ${t.desc}`);
});
if (p.case_study) {
  section('Proof: ' + (p.case_study.title || ''), () => {
    if (p.case_study.body) line(p.case_study.body);
    const m = (p.case_study.metrics || []).map((x) => `${x.value} ${x.label}`).join(' · ');
    if (m) bolds.push(line(m));
    if (p.case_study.relevance) line('Why this matters here: ' + p.case_study.relevance);
  });
}
section('Why HighCraft', () => bullets(p.why_us));
section('Investment', () => line(p.investment_note || ''));
section('Next steps', () => {
  (p.next_steps || []).forEach((s, i) => line(`${i + 1}. ${s}`));
  if ((p.call_slots || []).length) line('Suggested slots: ' + p.call_slots.join(' or '));
});
const off = 1;
const range = (r) => ({ startIndex: r[0] + off, endIndex: r[1] + off });
const requests = [{ insertText: { location: { index: 1 }, text } }];
requests.push({ updateParagraphStyle: { range: range(titleR), paragraphStyle: { namedStyleType: 'TITLE' }, fields: 'namedStyleType' } });
requests.push({ updateParagraphStyle: { range: range(subR), paragraphStyle: { namedStyleType: 'SUBTITLE' }, fields: 'namedStyleType' } });
requests.push({ updateTextStyle: { range: range(draftR), textStyle: { bold: true, foregroundColor: { color: { rgbColor: { red: 1, green: 0.34, blue: 0.34 } } } }, fields: 'bold,foregroundColor' } });
for (const r of h2s) requests.push({ updateParagraphStyle: { range: range(r), paragraphStyle: { namedStyleType: 'HEADING_2' }, fields: 'namedStyleType' } });
for (const r of bolds) requests.push({ updateTextStyle: { range: range(r), textStyle: { bold: true }, fields: 'bold' } });
for (const [s, e] of bulletRanges) requests.push({ createParagraphBullets: { range: { startIndex: s + off, endIndex: e + off }, bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE' } });
return [{ json: { requests } }];

