// Pull the first linkedin.com/company organic result from the Apify Google
// search output and fold it into the research summary.
const base = $('Distill research').first().json;
let linkedin_url = '', linkedin_summary = '';
try {
  const j = $input.first().json || {};
  const org = j.organicResults || [];
  const hit = org.find(r => /linkedin\.com\/company\//i.test(r.url || ''));
  if (hit) {
    linkedin_url = (hit.url || '').split('?')[0];
    const t = (hit.title || '').trim();
    const s = (hit.description || '').replace(/\s+/g, ' ').trim();
    linkedin_summary = (t + (s ? '. ' + s : '')).slice(0, 400);
  }
} catch (e) {}
let research_summary = base.research_summary || '';
if (linkedin_summary) {
  research_summary = (research_summary ? research_summary + '\n' : '') +
    'LINKEDIN (from a web search; verify it matches this company before using): ' + linkedin_summary + ' | ' + linkedin_url;
}
return [{ json: { ...base, linkedin_url, linkedin_summary, research_summary } }];
